"""Generate complete facts_kz_history.py with 470 facts."""
import json, sys

def w(f, tru, tkz, level, pru, pkz, oru, okz, corr, eru, ekz):
    f.write("    (\n")
    f.write(f'        "{level}",\n')
    f.write(f'        "{tru}", "{tkz}",\n')
    f.write(f'        "{pru}",\n')
    f.write(f'        "{pkz}",\n')
    f.write(f'        {json.dumps(oru, ensure_ascii=False)},\n')
    f.write(f'        {json.dumps(okz, ensure_ascii=False)},\n')
    f.write(f'        {corr},\n')
    f.write(f'        "{eru}",\n')
    f.write(f'        "{ekz}"\n')
    f.write("    ),\n")

def topic(f, num, tru, tkz, facts):
    f.write(f'    # {"=" * 63}\n')
    f.write(f'    # {num}. {tru} / {tkz}  ({len(facts)} facts)\n')
    f.write(f'    # {"=" * 63}\n')
    for item in facts:
        w(f, tru, tkz, *item)

